def bytes_to_human(n):
    for unit in ['B','KB','MB','GB','TB']:
        if n < 1024:
            return f"{n:.1f} {unit}"
        n /= 1024
    return f"{n:.1f} PB"

def seconds_to_human(s):
    d = int(s // 86400)
    h = int((s % 86400) // 3600)
    m = int((s % 3600) // 60)
    return f"{d}d {h}h {m}m"

def make_bar(p, w=30):
    filled = int(w * p / 100)
    return "[" + "#" * filled + "-" * (w - filled) + "]"


def plain_text_monitor(monitor):
    monitor.collect()
    monitor.start_background(interval=2.0)

    while True:
        try:
            time.sleep(1)
            d = monitor.data
            if not d:
                continue

            os.system('cls' if os.name == 'nt' else 'clear')

            print("="*60)
            print(f"SYSTEM MONITOR | {d['hostname']} | {d['timestamp']}")
            print(f"Uptime: {seconds_to_human(d['uptime'])}")
            print("="*60)

            cpu = d["cpu"]
            print("\nCPU")
            print(f"{cpu['percent']:5.1f}% {make_bar(cpu['percent'])}")

            mem = d["memory"]
            print("\nMEMORY")
            print(f"{mem['percent']:5.1f}% {make_bar(mem['percent'])}")

            disk = d["disk"]
            print("\nDISK")
            print(f"{disk['percent']:5.1f}% {make_bar(disk['percent'])}")

            net = d["network"]
            print("\nNETWORK")
            print(f"Up: {bytes_to_human(net['sent_speed'])}/s")
            print(f"Down: {bytes_to_human(net['recv_speed'])}/s")

            print("\nTop Processes")
            for p in d["processes"][:5]:
                print(f"{p['pid']:>6} {p['name'][:20]:<20} {p['cpu_percent']:5.1f}%")

            print("\nCtrl+C to quit")

        except KeyboardInterrupt:
            monitor.stop()
            break


